// Combined handler for S12 + S27 (Velocity module)
// Reproduced from actual 1.8.9 client source
@EventTarget
public void onReceive(EventReceivePacket event) {
  // Scale explosion knockback (same pattern as S12)
  if (event.getPacket() instanceof S27PacketExplosion) {
    S27PacketExplosion s27 =
      (S27PacketExplosion) event.getPacket();
    s27.motionX *= horizontal / 100.0;
    s27.motionY *= vertical / 100.0;
    s27.motionZ *= horizontal / 100.0;
  }

  // Cancel both S12 and S27 for full anti-KB
  if (event.getPacket() instanceof S27PacketExplosion
    || event.getPacket() instanceof S12PacketEntityVelocity) {
    event.setCancelled(true);
  }
}
